-- =====================================================
-- Feedback-Testdaten — Ruben Geyer (aus Forms-Excel 2024)
-- Idempotent: deterministische IDs + ON CONFLICT DO NOTHING.
-- Laeuft nur, wenn Rubens Athleten-Eintrag existiert. Entfernbar.
-- =====================================================
DO $$
DECLARE aid UUID;
BEGIN
  SELECT a.id INTO aid FROM athletes a JOIN auth.users u ON u.id=a.auth_user_id
   WHERE lower(u.email)='info@neue-weberei.de' LIMIT 1;
  IF aid IS NULL THEN RAISE NOTICE 'Ruben-Athlet nicht gefunden, skip'; RETURN; END IF;
  ON CONFLICT (id) DO NOTHING;
END $$;
